local lang = RSRG.Languages["es-es"]

-- Misiones de Maverick

-- Repartidor de misiones
lang["#MISSION_GIVER_MAVERICK"] = "Capitán Mercenario Maverick"
lang["#MISSION_GIVER_MAVERICK_SUBTITLE"] = "Caravana Cascade"
lang["#MISSION_GIVER_MAVERICK_GREET_UNKNOWN"] = "¿Eh? ¿Quién eres? ¿Otro refugiado? Toma asiento, podemos conseguirte algo de comer."
lang["#MISSION_GIVER_MAVERICK_GREET_NEW"] = "¿Otro nuevo? Espera, estás bastante bien equipado... Escucha, me llamo Maverick. Estamos en una situación de mierda aquí y podríamos usar algo de ayuda, y no me faltan tapas. ¿Te parece bien?"
lang["#MISSION_GIVER_MAVERICK_GREET_0"] = "Oye, artillero, tengo tapas, tú tienes un arma. Podemos hacer que esto funcione."
lang["#MISSION_GIVER_MAVERICK_GREET_100"] = "Estás haciendo un buen trabajo, estos refugiados están empezando a reconocerte, y debido a lo que estás haciendo, podemos enviar a más fuera de aquí. Tengo más trabajo si lo buscas."
lang["#MISSION_GIVER_MAVERICK_GREET_200"] = "Ah, $playername, buen trabajo abordando esta ciudad. Es un infierno, pero ver a algunas personas que realmente entienden lo que necesito es relajante. Hablando de eso..."
lang["#MISSION_GIVER_MAVERICK_GREET_400"] = "Las caravanas tienen un buen nombre para ti, me alegra ver que todavía estás pateando."
lang["#MISSION_GIVER_MAVERICK_GREET_FINISHED"] = "$playername, no tengo mucho más para ti ahora mismo. La ciudad todavía está llena de tecnología de antes de la guerra y botín, y las amenazas nunca se detendrán."

-- Misiones

lang["#MISSION_MAVERICK_ANTENNAREPAIR_NAME"] = "Reparación de Antena"
lang["#MISSION_MAVERICK_ANTENNAREPAIR_DESC"] = "Hay una vieja antena de radio que se está averiando. Sigo perdiendo contacto con los equipos en misiones, así que probablemente necesite piezas de repuesto. ¿Te importaría ir a echarle un vistazo?"
lang["#MISSION_MAVERICK_ANTENNAREPAIR_HINT"] = "Repara la Antena de Radio en las Ruinas de Salem. Sigue recto por la calle detrás de mí y gira a la izquierda después de pasar la iglesia. Puede que se necesite un buen conocimiento de ingeniería o un gran suministro de piezas de repuesto."

lang["#MISSION_MAVERICK_ANTENNAREPAIR_INTERACT"] = "Al abrir el interruptor de circuito conectado a la Antena, puedes ver que algo no está bien, ya que sale humo de los componentes internos corroídos. Sopesas tus opciones sobre cómo arreglar este desastre."

lang["#MISSION_MAVERICK_ANTENNAREPAIR_OPTION1_NAME"] = "Reparar las piezas existentes."
lang["#MISSION_MAVERICK_ANTENNAREPAIR_OPTION1_TEXT"] = "Parece que el acoplamiento de energía se está desgastando y apenas funciona, sin embargo, después de mirar de cerca, te das cuenta de que es fácil de arreglar con una llave inglesa."
lang["#MISSION_MAVERICK_ANTENNAREPAIR_OPTION1_COMPLETE"] = "Usando nada más que tu práctica llave inglesa, arreglas fácilmente la Antena."

lang["#MISSION_MAVERICK_ANTENNAREPAIR_OPTION2_NAME"] = "Reemplazar las piezas desgastadas."
lang["#MISSION_MAVERICK_ANTENNAREPAIR_OPTION2_TEXT"] = "Es difícil saber exactamente cuál es el problema, pero crees que si reemplazas algunas de las piezas más desgastadas, podrías hacer que vuelva a funcionar."
lang["#MISSION_MAVERICK_ANTENNAREPAIR_OPTION2_COMPLETE"] = "Reemplazas las piezas desgastadas por otras nuevas y... ¡Éxito! La Antena canta de nuevo."

lang["#MISSION_MAVERICK_ANTENNAREPAIR_OPTION3_NAME"] = "¡Reemplazar todo!"
lang["#MISSION_MAVERICK_ANTENNAREPAIR_OPTION3_TEXT"] = "La maraña de cables y circuitos no tiene sentido para ti. Lo único que se te ocurre es reemplazar cada pieza por algo que parezca similar."
lang["#MISSION_MAVERICK_ANTENNAREPAIR_OPTION3_COMPLETE"] = "Después de intercambiar piezas al azar, y de intentar y fallar múltiples veces, pateas la Antena por la frustración. Por algún milagro, comienza a funcionar."

lang["#MISSION_MAVERICK_SETTINGUP"] = "Preparándose, energía."
lang["#MISSION_MAVERICK_SETTINGUP_DESC"] = "Pareces capaz, más que los demás por aquí. Aquí está lo breve y conciso: toda esta ciudad se ha ido a la mierda. Los Sombríos están por todas partes, los mutantes intentan secuestrar a la gente por alguna maldita razón, y la policía se volvió a activar. Llegaste en una situación difícil.\n\n\nAsí que, si eres un mercenario, tengo algo de trabajo. Sé que hay una central eléctrica hacia la izquierda de aquí en algún lugar, pero no puedo prescindir de personal. Necesito que vayas allí y explores, dime en qué estado está el lugar, ¿vale, artillero?"
lang["#MISSION_MAVERICK_SETTINGUP_HINT"] = "Encuentra la Central Eléctrica de Salem. Maverick dijo que estaba a la izquierda del campamento en algún lugar."
lang["#MISSION_MAVERICK_SETTINGUP_COMPLETE"] = "¿Destrozada? ¿Saqueda por todo lo que valía? Malditos sombríos. Toma, pago."

lang["#MISSION_MAVERICK_HUNGRYMOUTHS"] = "Bocas Hambrientas."
lang["#MISSION_MAVERICK_HUNGRYMOUTHS_DESC"] = "Como puedes ver, tenemos una gran cantidad de refugiados aquí, personas que intentan ir al norte o que vienen del norte, que lo han perdido todo o no tenían nada para empezar. Un benefactor anónimo nos ha pagado para poner a estas personas de nuevo en pie y enviarlas de vuelta al sur, pero solo podemos llevar a unos pocos a la vez, teniendo los demás que quedarse hasta que nuestros guardias regresen por otro grupo, lo que lleva a esto.\n\nNecesito que vayas a buscar comida y bebida para estas personas, agua purificada, maíz y algo de carne de gecko. Hierve el maíz y cocina la carne. Recibirás tu recompensa por esto, no te preocupes."
lang["#MISSION_MAVERICK_HUNGRYMOUTHS_HINT"] = "Consigue 5 Aguas Purificadas, Maíz Hervido y 5 Carne de Gecko Cocida."
lang["#MISSION_MAVERICK_HUNGRYMOUTHS_COMPLETE"] = "Perfecto. Aquí tienes el pago y un regalo de uno de los refugiados."

lang["#MISSION_MAVERICK_THIEVINGISSUE"] = "El Problema de los Ladrones"
lang["#MISSION_MAVERICK_THIEVINGISSUE_DESC"] = "Bueno, esa central eléctrica es un maldito fracaso, y sé por qué, artillero. Puede que los hayas visto por aquí, pero hay un grupo de gente no muy amable que se hace llamar Los Sombríos. La única razón por la que sabemos eso es porque atrapamos a uno hace unas semanas e intentamos sacarle información, pero apenas escupió algo más que el nombre, y que venden lo que consiguen a un tercero, pero no dio nombres.\n\nEl punto es que mis tapas apuestan a que fueron ellos quienes desvalijaron toda la tecnología de ese lugar. Ve a eliminar a algunos de ellos, estoy harto de su mierda."
lang["#MISSION_MAVERICK_THIEVINGISSUE_HINT"] = "Mata a 25 Bandidos Sombríos. Se pueden encontrar alrededor de Salem."
lang["#MISSION_MAVERICK_THIEVINGISSUE_COMPLETE"] = "Genial, he visto cada vez menos de ellos. Buen trabajo, artillero."

lang["#MISSION_MAVERICK_DEADESTDELIVERY"] = "Entrega del Estuario Muerto"
lang["#MISSION_MAVERICK_DEADESTDELIVERY_DESC"] = "Oye, necesito que recojas algunas cosas. Esta es de Melvin en el Estuario Muerto. El tipo ha estado trabajando allí y tiene un barril lleno de Alga Atrayente que podemos usar para suministros médicos aquí. Ve a buscarlo, y recibirás una parte.\n\nMelvin debería estar en la pequeña Flotilla en la que invertimos demasiadas tapas, pero supongo que valió la pena."
lang["#MISSION_MAVERICK_DEADESTDELIVERY_HINT"] = "Recupera el barril de Alga Atrayente de Melvin en el Estuario Muerto, en la Flotilla Provisional."
lang["#MISSION_MAVERICK_DEADESTDELIVERY_COMPLETE"] = "No comiste nada, ¿verdad? Claro que no, aquí está tu parte, artillero."
lang["#MISSION_MAVERICK_DEADESTDELIVERY_ITEMNAME"] = "Barril de Alga Atrayente"

lang["#MISSION_MAVERICK_NEEDEDREPAIRS"] = "Algunas Reparaciones Necesarias"
lang["#MISSION_MAVERICK_NEEDEDREPAIRS_DESC"] = "Así que, un poco de tiempo de inactividad después de las matanzas, ¿eh? Bueno, necesitamos mantener algunas de las máquinas en funcionamiento mientras acampamos aquí, así que necesitamos algunos módulos sensores y conductores. Además, necesitamos una puta tonelada de metal de desecho para las paredas. Tiene un montón de agujeros por los disparos de los sombríos y las extrañas patrullas verdes. Además, necesitamos un poco más de protección de las autoridades locales."
lang["#MISSION_MAVERICK_NEEDEDREPAIRS_HINT"] = "Recoge 100 Metal de Desecho, 8 Módulos Sensores y 3 Conductores saqueando cajas de metal, cajas de herramientas y varias áreas."
lang["#MISSION_MAVERICK_NEEDEDREPAIRS_COMPLETE"] = "Un montón de basura. Aquí tienes algunas tapas y cosas que hacen que otros necesiten construcción."

lang["#MISSION_MAVERICK_MUTANTPATROLS"] = "Demasiados Mutantes"
lang["#MISSION_MAVERICK_MUTANTPATROLS_DESC"] = "¡Un maldito verde nos disparó cuando intentamos acercarnos al departamento de policía! Se apoderaron de las trincheras e hicieron una guerra de trincheras en este maldito lugar, ¡¿de dónde demonios salieron?!\n\nArtillero, recorre la ciudad y reduce sus números. Necesito intentar averiguar de dónde vienen, ¡malditas hordas de ellos apareciendo de la nada! Escucha, 20 tapas por cabeza, y obtendrás algunas cosas buenas para relajarte después, ¿de acuerdo?"
lang["#MISSION_MAVERICK_MUTANTPATROLS_HINT"] = "Mata a 15 Supermutantes en el mapa de Salem."
lang["#MISSION_MAVERICK_MUTANTPATROLS_COMPLETE"] = "Toma, algunas drogas y tapas. No juzgo, solo no lo hagas aquí. Asusta a los refugiados."

RELOADSCHEMA = true